import random

class FrameBuffer:
    """
    Frame Buffer: Core memory for raster displays.
    Stores every pixel's color value that gets displayed.
    Modern GPUs use frame buffers to render graphics.
    """

    def __init__(self, width, height, bits_per_pixel=24):
        self.width = width
        self.height = height
        self.bpp = bits_per_pixel
        # Allocate frame buffer memory (3 bytes per pixel for RGB)
        bytes_per_pixel = bits_per_pixel // 8
        self.buffer = bytearray(width * height * bytes_per_pixel)
        self.depth_buffer = [float('inf')] * (width * height)  # For z-buffer

    def _get_offset(self, x, y):
        """Convert 2D coordinate to 1D buffer index"""
        if 0 <= x < self.width and 0 <= y < self.height:
            return (y * self.width + x) * (self.bpp // 8)
        return -1

    def set_pixel(self, x, y, r, g, b, z=None):
        """Set pixel color at (x, y) with optional depth"""
        offset = self._get_offset(x, y)
        if offset >= 0:
            self.buffer[offset] = b      # Blue
            self.buffer[offset + 1] = g  # Green
            self.buffer[offset + 2] = r  # Red

            if z is not None and self.depth_buffer:
                idx = y * self.width + x
                self.depth_buffer[idx] = z

    def get_pixel(self, x, y):
        """Get pixel color at (x, y)"""
        offset = self._get_offset(x, y)
        if offset >= 0:
            b = self.buffer[offset]
            g = self.buffer[offset + 1]
            r = self.buffer[offset + 2]
            return (r, g, b)
        return (0, 0, 0)

    def clear(self, r=0, g=0, b=0):
        """Clear entire frame buffer"""
        for i in range(0, len(self.buffer), 3):
            self.buffer[i] = b
            self.buffer[i+1] = g
            self.buffer[i+2] = r
        self.depth_buffer = [float('inf')] * len(self.depth_buffer)

    def render_to_console(self):
        """ASCII art representation of frame buffer"""
        print(f"Frame Buffer ({self.width}x{self.height}):")
        for y in range(self.height):
            row = ""
            for x in range(self.width):
                r, g, b = self.get_pixel(x, y)
                brightness = (r + g + b) // 3
                if brightness > 200:
                    row += "█"
                elif brightness > 100:
                    row += "▓"
                elif brightness > 50:
                    row += "▒"
                elif brightness > 0:
                    row += "░"
                else:
                    row += " "
            print(row)

# Demonstrate frame buffer operations
fb = FrameBuffer(40, 20)

# Draw a filled rectangle (raster graphics primitive)
def draw_rectangle(fb, x1, y1, x2, y2, r, g, b):
    for y in range(y1, y2 + 1):
        for x in range(x1, x2 + 1):
            fb.set_pixel(x, y, r, g, b)

# Draw diagonal line using Bresenham's algorithm
def draw_line(fb, x1, y1, x2, y2, r, g, b):
    dx = abs(x2 - x1)
    dy = abs(y2 - y1)
    sx = 1 if x1 < x2 else -1
    sy = 1 if y1 < y2 else -1
    err = dx - dy

    while True:
        fb.set_pixel(x1, y1, r, g, b)
        if x1 == x2 and y1 == y2:
            break
        e2 = 2 * err
        if e2 > -dy:
            err -= dy
            x1 += sx
        if e2 < dx:
            err += dx
            y1 += sy

# Create simple scene
fb.clear(0, 0, 0)
draw_rectangle(fb, 5, 3, 15, 8, 255, 0, 0)    # Red rectangle
draw_rectangle(fb, 20, 10, 35, 17, 0, 255, 0)  # Green rectangle
draw_line(fb, 0, 0, 39, 19, 255, 255, 0)       # Yellow diagonal

fb.render_to_console()
print(f"\nFrame buffer size: {len(fb.buffer)} bytes")
print(f"Resolution: {fb.width}x{fb.height} = {fb.width * fb.height} pixels")
